import { runAllAnalytics } from '../lib/analytics'
import { useState, useEffect } from 'react'
import { getAuthUrl, getConnectionStatus, syncToday, backfill, getSyncLog } from '../lib/googleSync'
import { pushSupported, permission, getSubscription, enablePush, disablePush, sendTestNotification } from '../lib/push'

const todayKey = () => {
  const d = new Date()
  return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}-${String(d.getDate()).padStart(2, '0')}`
}

const btnPrimary = { minHeight: 44, padding: '0 16px', borderRadius: 10, border: 'none', background: 'var(--indigo)', color: '#fff', fontSize: 13.5, fontWeight: 600, cursor: 'pointer', fontFamily: 'inherit' }
const btnGhost = { minHeight: 44, padding: '0 16px', borderRadius: 10, border: '1.5px solid var(--bd)', background: 'var(--bg)', color: 'var(--ink2)', fontSize: 13.5, fontWeight: 600, cursor: 'pointer', fontFamily: 'inherit' }

export default function More({ showToast, openMetric, openHeart }) {
  const [insights, setInsights] = useState([])
  const [loading, setLoading] = useState(true)
  const [conn, setConn] = useState({ connected: false })
  const [syncing, setSyncing] = useState(false)
  const [syncResult, setSyncResult] = useState(null)
  const [syncRows, setSyncRows] = useState([])
  const [showDebug, setShowDebug] = useState(false)
  const [log, setLog] = useState([])
  const [pushOn, setPushOn] = useState(false)
  const [pushBusy, setPushBusy] = useState(false)
  const [pushNote, setPushNote] = useState('')

  useEffect(() => {
    getSubscription().then(sub => setPushOn(!!sub)).catch(() => {})
    refreshStatus()
    // Google bounces back here with ?google=connected|error after consent.
    const q = new URLSearchParams(window.location.search)
    if (q.get('google')) {
      const ok = q.get('google') === 'connected'
      showToast(ok ? 'Fitbit connected' : 'Connection failed', ok ? 'var(--green)' : 'var(--red)')
      if (!ok && q.get('detail')) setSyncResult({ error: q.get('detail') })
      window.history.replaceState({}, document.title, window.location.pathname)
    }
    // eslint-disable-next-line
  }, [])

  async function refreshStatus() {
    const st = await getConnectionStatus()
    setConn(st)
    setSyncRows(await getSyncLog(5))
  }

  async function togglePush() {
    setPushBusy(true); setPushNote('')
    const res = pushOn ? await disablePush() : await enablePush()
    if (res.ok) {
      setPushOn(!pushOn)
      showToast(pushOn ? 'Reminders off' : 'Reminders on', pushOn ? undefined : 'var(--green)')
    } else {
      setPushNote(res.reason || 'Could not change notification settings.')
      showToast('Not changed', 'var(--red)')
    }
    setPushBusy(false)
  }

  async function testPush() {
    const res = await sendTestNotification()
    if (!res.ok) { setPushNote(res.reason); showToast('Test failed', 'var(--red)') }
  }

  useEffect(() => {
    runAllAnalytics().then(r => {
      setInsights(r?.insights?.slice(0, 4) || [])
      setLoading(false)
    }).catch(() => setLoading(false))
  }, [])

  // Runs a real snapshot and shows exactly what came back, so a failure is
  // visible as a status code rather than an empty screen.
  async function syncNow() {
    setSyncing(true); setSyncResult(null)
    const r = await syncToday()
    setSyncResult(r)
    showToast(
      r.ok ? (r.metrics_written ? `Synced — ${r.metrics_written} metrics` : 'Connected, but Google returned nothing')
           : 'Sync failed',
      r.ok && r.metrics_written ? 'var(--green)' : r.ok ? 'var(--amber)' : 'var(--red)')
    await refreshStatus()
    setSyncing(false)
  }

  async function runBackfill() {
    setSyncing(true); setSyncResult(null)
    const r = await backfill(14)
    setSyncResult(r)
    const days = r.results ? Object.values(r.results).filter(n => n > 0).length : 0
    showToast(r.ok ? `Backfilled ${days} days` : 'Backfill failed', r.ok ? 'var(--green)' : 'var(--red)')
    await refreshStatus()
    setSyncing(false)
  }


  return (
    <div className="screen active">
      <div className="header" style={{ paddingBottom: 16 }}>
        <div className="page-title">More</div>
      </div>
      <div className="body">
        <div className="section-label">Top insights {!loading && `(${insights.length} found)`}</div>
        {loading && <div className="mono" style={{ fontSize: 10, color: 'var(--ink3)', textAlign: 'center', padding: 20 }}>Running analysis...</div>}
        {!loading && insights.length === 0 && (
          <div className="card" style={{ padding: 16 }}>
            <div style={{ fontSize: 13, color: 'var(--ink2)', lineHeight: 1.65 }}>Log symptom scores daily for at least 5 days to start seeing correlations. The more you log, the more patterns emerge.</div>
          </div>
        )}
        {insights.map((card, i) => (
          <div key={i} className="insight-card" style={{ borderColor: card.color + '40', marginBottom: 8 }}>
            <div className="mono" style={{ fontSize: 8.5, color: card.color, textTransform: 'uppercase', letterSpacing: '.08em', fontWeight: 600, marginBottom: 5 }}>
              {card.color === 'var(--green)' ? '↓ Helps' : '↑ Raises'} · {card.impact} pt impact · n={card.n}
            </div>
            <div style={{ fontSize: 13.5, fontWeight: 700, color: 'var(--ink)', marginBottom: 4, lineHeight: 1.3 }}>{card.headline}</div>
            <div style={{ fontSize: 12, color: 'var(--ink2)', lineHeight: 1.55 }}>{card.body}</div>
          </div>
        ))}

        {/* ── REMINDERS ────────────────────────────────────── */}
        <div className="section-label" style={{ marginTop: 4 }}>Reminders</div>
        <div className="card" style={{ padding: 16 }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 6 }}>
            <span style={{ width: 8, height: 8, borderRadius: 4, background: pushOn ? 'var(--green)' : 'var(--ink4)' }} />
            <div style={{ fontSize: 13.5, fontWeight: 700 }}>{pushOn ? 'Scheduled reminders on' : 'Scheduled reminders off'}</div>
          </div>
          <div style={{ fontSize: 12, color: 'var(--ink2)', lineHeight: 1.55, marginBottom: 12 }}>
            {pushSupported()
              ? 'Prompts fire at their scheduled time with Done and Skip buttons, so you can log without opening the app.'
              : 'This browser does not support push notifications.'}
          </div>

          <div style={{
            fontSize: 11.5, lineHeight: 1.5, color: '#7A4500', background: 'var(--amber-xl)',
            border: '1px solid var(--amber)', borderRadius: 8, padding: '8px 10px', marginBottom: 12,
          }}>
            Web push is best-effort — Android battery saver can delay or drop it.
            Keep a phone alarm for the 17:30 propranolol dose.
          </div>

          <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap' }}>
            <button disabled={pushBusy || !pushSupported()} onClick={togglePush} style={{
              minHeight: 44, padding: '0 16px', borderRadius: 10, border: pushOn ? '1.5px solid var(--bd)' : 'none',
              background: pushOn ? 'var(--bg)' : 'var(--indigo)', color: pushOn ? 'var(--ink2)' : '#fff',
              fontSize: 13.5, fontWeight: 600, cursor: 'pointer', opacity: pushBusy ? .6 : 1,
            }}>
              {pushBusy ? '…' : pushOn ? 'Turn off' : 'Turn on reminders'}
            </button>
            {pushOn && (
              <button onClick={testPush} style={{
                minHeight: 44, padding: '0 16px', borderRadius: 10, border: '1.5px solid var(--bd)',
                background: 'var(--bg)', color: 'var(--ink2)', fontSize: 13.5, fontWeight: 600, cursor: 'pointer',
              }}>Send test</button>
            )}
          </div>

          {pushNote && (
            <div className="mono" style={{ fontSize: 10.5, color: 'var(--red)', marginTop: 10, lineHeight: 1.5 }}>{pushNote}</div>
          )}
          <div className="mono" style={{ fontSize: 9.5, color: 'var(--ink4)', marginTop: 8 }}>
            permission: {permission()}
          </div>
        </div>

        {/* ── FITBIT / GOOGLE HEALTH ───────────────────────── */}
        <div className="section-label" style={{ marginTop: 4 }}>Fitbit</div>
        <div className="card" style={{ padding: 16 }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 6 }}>
            <span style={{ width: 8, height: 8, borderRadius: 4, background: conn.connected ? 'var(--green)' : 'var(--ink4)' }} />
            <div style={{ fontSize: 13.5, fontWeight: 700 }}>{conn.connected ? 'Connected' : 'Not connected'}</div>
          </div>
          <div style={{ fontSize: 12, color: 'var(--ink2)', lineHeight: 1.55, marginBottom: 12 }}>
            {conn.connected
              ? 'Syncing on a schedule in the background — you no longer need to reconnect or open the app for data to save.'
              : 'Link your Google account once. The connection is kept alive server-side, so it stays connected.'}
          </div>

          {conn.lastRefreshAt && (
            <div className="mono" style={{ fontSize: 10, color: 'var(--ink3)', marginBottom: 10 }}>
              token refreshed {new Date(conn.lastRefreshAt).toLocaleString('en-US', { month: 'short', day: 'numeric', hour: 'numeric', minute: '2-digit' })}
            </div>
          )}
          {conn.lastError && (
            <div className="mono" style={{ fontSize: 10, color: 'var(--red)', marginBottom: 10 }}>{conn.lastError}</div>
          )}

          <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap' }}>
            {!conn.connected && (
              <button onClick={() => { window.location.href = getAuthUrl() }} style={btnPrimary}>Connect Fitbit</button>
            )}
            {conn.connected && (
              <>
                <button onClick={syncNow} disabled={syncing} style={{ ...btnPrimary, opacity: syncing ? .6 : 1 }}>
                  {syncing ? 'Syncing…' : 'Sync now'}
                </button>
                <button onClick={runBackfill} disabled={syncing} style={btnGhost}>Backfill 14 days</button>
              </>
            )}
          </div>

          {syncResult?.error && (
            <div className="mono" style={{ fontSize: 10, color: 'var(--red)', marginTop: 10, wordBreak: 'break-word' }}>{syncResult.error}</div>
          )}

          {syncRows.length > 0 && (
            <div style={{ marginTop: 14, borderTop: '1px solid var(--bd)', paddingTop: 10 }}>
              <div className="eyebrow" style={{ marginBottom: 6 }}>Recent syncs</div>
              {syncRows.map(r => (
                <div key={r.id} style={{ display: 'flex', justifyContent: 'space-between', fontSize: 11, padding: '2px 0' }}>
                  <span className="mono" style={{ color: 'var(--ink3)' }}>{r.target_date}</span>
                  <span className="mono" style={{ color: r.ok ? 'var(--green)' : 'var(--red)' }}>
                    {r.ok ? `${r.metrics_written} metrics` : (r.detail || 'failed').slice(0, 34)}
                  </span>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* ── NOT YET BUILT ────────────────────────────────── */}
        {/* Heart monitor is reachable now -- it holds the episode walkthrough. */}
        <div className="section-label" style={{ marginTop: 4 }}>During an episode</div>
        <div className="card">
          <div className="row" onClick={openHeart} style={{ cursor: 'pointer' }}>
            <div style={{ flex: 1 }}>
              <div style={{ fontSize: 13.5, fontWeight: 600, color: 'var(--ink)' }}>Heart monitor</div>
              <div style={{ fontSize: 11.5, color: 'var(--ink3)', marginTop: 2 }}>Episode walkthrough · Rylie&rsquo;s view</div>
            </div>
            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="var(--ink4)" strokeWidth="2"><polyline points="9 18 15 12 9 6" /></svg>
          </div>
        </div>

        <div className="section-label" style={{ marginTop: 4 }}>Not yet built</div>
        <div className="card">
          {[
            { label: 'Medications', sub: 'View your full medication list' },
            { label: 'Wellness plan', sub: 'Foundation phase protocol' },
            { label: 'Analytics', sub: 'Full correlation dashboard' },
          ].map((item, i, arr) => (
            <div key={item.label} className="row" style={{ borderBottom: i < arr.length - 1 ? '1px solid var(--bd)' : 'none', opacity: .5 }}>
              <div style={{ flex: 1 }}>
                <div style={{ fontSize: 13.5, fontWeight: 600, color: 'var(--ink)' }}>{item.label}</div>
                {item.sub && <div style={{ fontSize: 11.5, color: 'var(--ink3)', marginTop: 2 }}>{item.sub}</div>}
              </div>
              <span className="mono" style={{ fontSize: 9, color: 'var(--ink4)' }}>SOON</span>
            </div>
          ))}
        </div>
      </div>
    </div>
  )
}
